'use client';

import * as React from 'react';
import { AppBar, Box, Toolbar, Typography, IconButton, Menu as MuiMenu, MenuItem, Drawer, List, ListItemButton, ListItemIcon, ListItemText, CssBaseline, Divider, Container, Link as MuiLink } from '@mui/material';
import MenuIcon from '@mui/icons-material/Menu';
import HomeIcon from '@mui/icons-material/Home';
import PointOfSaleIcon from '@mui/icons-material/PointOfSale';
import PrintIcon from '@mui/icons-material/Print';
import AssessmentIcon from '@mui/icons-material/Assessment';
import SettingsIcon from '@mui/icons-material/Settings';
import GitHubIcon from '@mui/icons-material/GitHub';
import CloseIcon from '@mui/icons-material/Close';
import { usePathname, useRouter } from 'next/navigation';

/**
 * MUI Header, Footer, and Side Menu in one TSX file.
 * - Responsive Drawer (temporary on mobile, persistent on desktop)
 * - Top AppBar with overflow (Avatar/Settings) menu
 * - Footer sticks to bottom
 * - Layout component wraps your pages
 *
 * Usage (Next.js App Router):
 *   export default function Page() {
 *     return (
 *       <AppLayout title="Dashboard">
 *         <YourPageContent />
 *       </AppLayout>
 *     );
 *   }
 */

const drawerWidth = 260;

// --- Types ---
export type NavItem = {
  label: string;
  href: string;
  icon?: React.ReactNode;
};

// --- Navigation Items (edit to your app) ---
const NAV_ITEMS: NavItem[] = [
  { label: 'Home', href: '/', icon: <HomeIcon /> },
  { label: 'POS', href: '/pos', icon: <PointOfSaleIcon /> },
  { label: 'Print Jobs', href: '/print-jobs', icon: <PrintIcon /> },
  { label: 'Reports', href: '/reports', icon: <AssessmentIcon /> },
  { label: 'Settings', href: '/settings', icon: <SettingsIcon /> },
];

// --- Header ---
export function Header({ title, onOpenMenu }: { title?: string; onOpenMenu?: () => void }) {
  const [anchorEl, setAnchorEl] = React.useState<null | HTMLElement>(null);
  const isOpen = Boolean(anchorEl);

  return (
    <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
      <Toolbar>
        <IconButton
          color="inherit"
          edge="start"
          onClick={onOpenMenu}
          sx={{ mr: 2, display: { xs: 'inline-flex', md: 'none' } }}
          aria-label="open menu"
        >
          <MenuIcon />
        </IconButton>
        <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
          {title ?? 'My App'}
        </Typography>
        <IconButton color="inherit" onClick={(e) => setAnchorEl(e.currentTarget)} aria-label="more">
          <SettingsIcon />
        </IconButton>
        <MuiMenu anchorEl={anchorEl} open={isOpen} onClose={() => setAnchorEl(null)}>
          <MenuItem onClick={() => setAnchorEl(null)}>Profile</MenuItem>
          <MenuItem onClick={() => setAnchorEl(null)}>Preferences</MenuItem>
          <Divider />
          <MenuItem component={MuiLink} href="https://github.com" target="_blank" rel="noreferrer">
            <ListItemIcon sx={{ minWidth: 32 }}><GitHubIcon fontSize="small" /></ListItemIcon>
            <ListItemText>GitHub</ListItemText>
          </MenuItem>
        </MuiMenu>
      </Toolbar>
    </AppBar>
  );
}

// --- Side Menu ---
export function SideMenu({ items = NAV_ITEMS, open, onClose }: { items?: NavItem[]; open: boolean; onClose: () => void }) {
  const pathname = usePathname?.() ?? '/';
  const router = useRouter?.();

  const list = (
    <Box role="presentation" sx={{ width: { xs: 280, sm: drawerWidth } }}>
      <Toolbar sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', px: 2 }}>
        <Typography variant="subtitle1" fontWeight={700}>Menu</Typography>
        <IconButton onClick={onClose} aria-label="close menu"><CloseIcon /></IconButton>
      </Toolbar>
      <Divider />
      <List>
        {items.map((item) => {
          const active = pathname === item.href;
          return (
            <ListItemButton
              key={item.href}
              selected={active}
              onClick={() => {
                onClose();
                router?.push(item.href);
              }}
            >
              {item.icon ? <ListItemIcon>{item.icon}</ListItemIcon> : null}
              <ListItemText primary={item.label} />
            </ListItemButton>
          );
        })}
      </List>
    </Box>
  );

  return (
    <>
      {/* Mobile */}
      <Drawer
        variant="temporary"
        open={open}
        onClose={onClose}
        ModalProps={{ keepMounted: true }}
        sx={{ display: { xs: 'block', md: 'none' } }}
      >
        {list}
      </Drawer>

      {/* Desktop */}
      <Drawer
        variant="permanent"
        sx={{
          display: { xs: 'none', md: 'block' },
          '& .MuiDrawer-paper': { width: drawerWidth, boxSizing: 'border-box' },
        }}
        open
      >
        <Toolbar />
        {list}
      </Drawer>
    </>
  );
}

// --- Footer ---
export function Footer() {
  return (
    <Box component="footer" sx={{ mt: 'auto', py: 2, borderTop: 1, borderColor: 'divider' }}>
      <Container maxWidth="lg" sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 2 }}>
        <Typography variant="body2" color="text.secondary">
          © {new Date().getFullYear()} Print POS — All rights reserved.
        </Typography>
        <Typography variant="body2" color="text.secondary">
          Built with MUI
        </Typography>
      </Container>
    </Box>
  );
}

// --- Layout ---
export default function AppLayout({ title, children }: { title?: string; children: React.ReactNode }) {
  const [mobileOpen, setMobileOpen] = React.useState(false);

  return (
    <Box sx={{ display: 'flex', minHeight: '100dvh' }}>
      <CssBaseline />

      <Header title={title} onOpenMenu={() => setMobileOpen(true)} />

      <SideMenu open={mobileOpen} onClose={() => setMobileOpen(false)} />

      <Box component="main" sx={{ flexGrow: 1, p: { xs: 2, md: 3 }, ml: { md: `${drawerWidth}px` } }}>
        <Toolbar />
        <Container maxWidth="lg">
          {children}
        </Container>
        <Footer />
      </Box>
    </Box>
  );
}

// --- Example page content (remove in production) ---
export function ExampleContent() {
  return (
    <Box sx={{ display: 'grid', gap: 2 }}>
      <Typography variant="h4" fontWeight={700}>Welcome to Print POS</Typography>
      <Typography color="text.secondary">
        This is a placeholder. Replace with your page content.
      </Typography>
    </Box>
  );
}